Toàn bộ logic upload nằm trong App.jsx. Quy trình gồm 2 bước rõ ràng:
Bước 1: Gọi API lấy presigned URL
Bước 2: PUT file thẳng lên S3 với URL đó
Validate file trước khi gọi API:
// src/App.jsx const ALLOWED_TYPES = [ &#39;application/pdf&#39;, &#39;application/vnd.openxmlformats-officedocument.wordprocessingml.document&#39;, &#39;application/msword&#39; ] const MAX_SIZE_MB = 5 function handleFile(f) { if (!f) return if (!ALLOWED_TYPES.includes(f.type)) { setMessage(&#39;Chỉ chấp nhận file PDF, DOCX hoặc DOC.&#39;) return } if (f.size &gt; MAX_SIZE_MB * 1024 * 1024) { setMessage(`File quá lớn. Tối đa ${MAX_SIZE_MB}MB.`) return } setFile(f) setMessage(&#39;&#39;) } Vấn đề thực tế — browser báo sai Content-Type: Trên một số trình duyệt (đặc biệt macOS Safari), file.type của file .pdf có thể trả về chuỗi rỗng &quot;&quot;. Nếu dùng trực tiếp file.type để set Content-Type khi PUT lên S3 → Signature mismatch vì Lambda đã sign với application/pdf. Giải pháp: map từ extension file:
// src/App.jsx const EXT_TO_TYPE = { &#39;.pdf&#39;: &#39;application/pdf&#39;, &#39;.docx&#39;: &#39;application/vnd.openxmlformats-officedocument.wordprocessingml.document&#39;, &#39;.doc&#39;: &#39;application/msword&#39;, } function _contentTypeFor(file) { const name = (file?.name || &#39;&#39;).toLowerCase() const dot = name.lastIndexOf(&#39;.&#39;) if (dot &gt;= 0) { const t = EXT_TO_TYPE[name.slice(dot)] if (t) return t } return file?.type || &#39;application/octet-stream&#39; } Submit handler — 2 bước upload:
// src/App.jsx async function handleSubmit(e) { e.preventDefault() if (!jobId.trim()) { setMessage(&#39;Vui lòng chọn vị trí.&#39;); return } if (!file) { setMessage(&#39;Vui lòng chọn file CV.&#39;); return } setStatus(&#39;uploading&#39;) // Bước 1: Lấy presigned URL từ API Gateway → Lambda let data try { const resp = await axios.get(`${API_BASE}/apply/presigned-url`, { params: { job_id: jobId.trim(), file_name: file.name } }) data = resp.data } catch (err) { const apiMsg = err.response?.data?.error || err.message setStatus(&#39;error&#39;) setMessage(`Bước 1 (lấy URL) thất bại: ${apiMsg}`) return } // Bước 2: Upload thẳng lên S3 (KHÔNG qua Lambda) try { const contentType = _contentTypeFor(file) const arrayBuffer = await file.arrayBuffer() // đọc file thành binary await axios.put(data.presigned_url, arrayBuffer, { headers: { &#39;Content-Type&#39;: contentType, // phải khớp với URL đã sign &#39;x-amz-meta-channel&#39;: &#39;web&#39;, &#39;x-amz-meta-job_id&#39;: jobId.trim() }, onUploadProgress: (e) =&gt; { if (e.total &gt; 0) { const pct = Math.round((e.loaded / e.total) * 100) setMessage(`Đang tải lên... ${pct}%`) } } }) } catch (err) { setStatus(&#39;error&#39;) const status = err.response?.status const friendly = status === 403 ? &#39;URL hết hạn hoặc sai chữ ký. Thử lại.&#39; : status === 400 ? &#39;S3 từ chối file (Content-Type có thể sai).&#39; : &#39;Upload lên S3 thất bại.&#39; setMessage(`${friendly} (HTTP ${status || &#39;?&#39;})`) return } setStatus(&#39;success&#39;) setFile(null) } Tại sao dùng file.arrayBuffer() thay vì gửi file trực tiếp: Axios khi nhận File object có thể tự thêm Content-Type: multipart/form-data vào request. S3 presigned URL đã sign với application/pdf → mismatch → 403. Convert sang ArrayBuffer trước khi PUT đảm bảo axios không override Content-Type header.

cd candidate-app # Build production bundle npm run build # → tạo thư mục dist/ với index.html, JS, CSS đã minify # Upload lên S3 bucket frontend aws s3 sync dist/ s3://hireflow-candidate-226593872610/ \ --delete \ --cache-control &#34;max-age=31536000,immutable&#34; # JS/CSS hash → cache 1 năm # index.html không cache để deploy mới có hiệu lực ngay aws s3 cp dist/index.html s3://hireflow-candidate-226593872610/index.html \ --cache-control &#34;no-cache,no-store,must-revalidate&#34; # Invalidate CloudFront cache aws cloudfront create-invalidation \ --distribution-id &lt;DISTRIBUTION_ID&gt; \ --paths &#34;/*&#34; Tại sao phân biệt cache-control giữa index.html và assets: Vite build tạo ra tên file JS/CSS có hash nội dung (ví dụ index-Bx3kP9aZ.js) — hash thay đổi khi code đổi nên cache vĩnh viễn an toàn. index.html không có hash, phải no-cache để người dùng luôn nhận bản mới nhất chứa đúng tên file JS.
Cấu hình S3 bucket cho static hosting:
# Bật static website hosting aws s3 website s3://hireflow-candidate-226593872610/ \ --index-document index.html \ --error-document index.html # SPA routing: 404 về index.html # Set bucket policy public read (hoặc dùng CloudFront OAC) aws s3api put-bucket-policy \ --bucket hireflow-candidate-226593872610 \ --policy &#39;{ &#34;Version&#34;: &#34;2012-10-17&#34;, &#34;Statement&#34;: [{ &#34;Effect&#34;: &#34;Allow&#34;, &#34;Principal&#34;: &#34;*&#34;, &#34;Action&#34;: &#34;s3:GetObject&#34;, &#34;Resource&#34;: &#34;arn:aws:s3:::hireflow-candidate-226593872610/*&#34; }] }&#39;
